import java.util.Scanner;
import java.util.Date;
import java.text.SimpleDateFormat;

/**
 * Task 1: Food Restaurant Menu Billing
 * Description: Displays menu, takes order, calculates bill with GST.
 */
public class RestaurantBilling {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int choice, quantity;
        double total = 0.0;
        String orderDetails = "";
        boolean ordering = true;

        System.out.println("=========================================");
        System.out.println("         MANUU RESTAURANT SYSTEM         ");
        System.out.println("=========================================");

        while (ordering) {
            System.out.println("\n--- Food Menu ---");
            System.out.println("1. Biryani (Rs. 180)");
            System.out.println("2. Chicken 65 (Rs. 150)");
            System.out.println("3. Paneer Butter Masala (Rs. 160)");
            System.out.println("4. Naan (Rs. 20)");
            System.out.println("5. Finish Order and Generate Bill");
            System.out.print("Enter your choice (1-5): ");

            // Simulated inputs for output generation
            choice = Integer.parseInt(sc.nextLine());

            if (choice == 5) {
                ordering = false;
                break;
            }

            System.out.print("Enter quantity: ");
            quantity = Integer.parseInt(sc.nextLine());
            double price = 0;
            String itemName = "";

            switch (choice) {
                case 1: price = 180; itemName = "Biryani"; break;
                case 2: price = 150; itemName = "Chicken 65"; break;
                case 3: price = 160; itemName = "Paneer Butter Masala"; break;
                case 4: price = 20; itemName = "Naan"; break;
                default: System.out.println("Invalid choice!"); continue;
            }

            double itemTotal = price * quantity;
            total += itemTotal;
            orderDetails += String.format("%-22s | %-4d | Rs. %-6.2f | Rs. %.2f\n", itemName, quantity, price, itemTotal);
        }

        double gst = total * 0.05; // 5% GST
        double grandTotal = total + gst;

        System.out.println("\n=======================================================");
        System.out.println("                     FINAL INVOICE                     ");
        System.out.println("=======================================================");
        SimpleDateFormat formatter = new SimpleDateFormat("dd/MM/yyyy HH:mm:ss");
        System.out.println("Date & Time : " + formatter.format(new Date()));
        System.out.println("Customer    : {studentName}");
        System.out.println("Roll No     : {rollNumber}");
        System.out.println("-------------------------------------------------------");
        System.out.printf("%-22s | Qty  | Price      | Total\n", "Item Name");
        System.out.println("-------------------------------------------------------");
        System.out.print(orderDetails);
        System.out.println("-------------------------------------------------------");
        System.out.printf("Sub Total                        : Rs. %.2f\n", total);
        System.out.printf("GST (5%%)                         : Rs. %.2f\n", gst);
        System.out.println("-------------------------------------------------------");
        System.out.printf("GRAND TOTAL                      : Rs. %.2f\n", grandTotal);
        System.out.println("=======================================================");
        System.out.println("          Thank you for dining with us!                ");
        sc.close();
    }
}

import java.util.Scanner;
import java.util.Date;
import java.text.SimpleDateFormat;

/**
 * Task 2: Electricity Bill Generator
 * Description: Calculate electricity bill based on units consumed for Domestic/Commercial use.
 */
public class ElectricityBill {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);

        System.out.println("*** Electricity Bill Calculator ***\n");
        System.out.println("1. Domestic (Rs. 3.50/unit for first 100, Rs. 5.00/unit above)");
        System.out.println("2. Commercial (Rs. 7.00/unit for first 100, Rs. 10.00/unit above)");
        System.out.print("Select connection type (1 or 2): ");
        int type = Integer.parseInt(sc.nextLine());

        System.out.print("Enter units consumed: ");
        int units = Integer.parseInt(sc.nextLine());

        double billAmount = 0.0;
        String connectionType = "";

        if (type == 1) {
            connectionType = "Domestic";
            if (units <= 100) {
                billAmount = units * 3.50;
            } else {
                billAmount = (100 * 3.50) + ((units - 100) * 5.00);
            }
        } else if (type == 2) {
            connectionType = "Commercial";
            if (units <= 100) {
                billAmount = units * 7.00;
            } else {
                billAmount = (100 * 7.00) + ((units - 100) * 10.00);
            }
        } else {
            System.out.println("Invalid connection type!");
            sc.close();
            return;
        }

        System.out.println("\n========================================");
        System.out.println("            ELECTRICITY BILL            ");
        System.out.println("========================================");
        SimpleDateFormat formatter = new SimpleDateFormat("dd/MM/yyyy HH:mm:ss");
        System.out.println("Billing Date : " + formatter.format(new Date()));
        System.out.println("Consumer Name: {studentName}");
        System.out.println("Consumer ID  : ER-" + {rollNumber});
        System.out.println("----------------------------------------");
        System.out.println("Connection   : " + connectionType);
        System.out.println("Units Used   : " + units);
        System.out.printf("Total Amount : Rs. %.2f\n", billAmount);
        System.out.println("========================================\n");
        sc.close();
    }
}

import java.util.Scanner;
import java.util.Date;
import java.text.SimpleDateFormat;

/**
 * Task 3: CGPA Calculator
 * Description: Calculate CGPA and percentage from grades.
 */
public class CGPACalculator {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        System.out.println("--- CGPA & PERCENTAGE CALCULATOR ---");
        System.out.print("Enter number of subjects: ");
        int subjects = Integer.parseInt(sc.nextLine());

        double totalGradePoints = 0;
        for (int i = 1; i <= subjects; i++) {
            System.out.print("Enter Grade Point (0-10) for subject " + i + ": ");
            double gp = Double.parseDouble(sc.nextLine());
            totalGradePoints += gp;
        }

        double cgpa = totalGradePoints / subjects;
        double percentage = cgpa * 9.5; // Standard formula to convert CGPA to %

        System.out.println("\n==========================================");
        System.out.println("            ACADEMIC REPORT             ");
        System.out.println("==========================================");
        SimpleDateFormat formatter = new SimpleDateFormat("dd/MMM/yyyy HH:mm:ss");
        System.out.println("Generated On : " + formatter.format(new Date()));
        System.out.println("Student Name : {studentName}");
        System.out.println("Roll Number  : {rollNumber}");
        System.out.println("------------------------------------------");
        System.out.printf("Calculated CGPA : %.2f / 10.0\n", cgpa);
        System.out.printf("Equivalent %%    : %.2f %%\n", percentage);
        System.out.println("==========================================");
        sc.close();
    }
}

import java.util.Scanner;
