/**
 * Task 4: Quiz Application
 * Description: A basic multiple choice quiz application.
 */
public class QuizApp {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int score = 0;

        System.out.println("****************************************");
        System.out.println("         JAVA PROGRAMMING QUIZ          ");
        System.out.println("****************************************");
        System.out.println("Welcome, {studentName} ({rollNumber})\n");

        // Q1
        System.out.println("Q1. Who invented Java Programming?");
        System.out.println("a) Guido van Rossum\nb) James Gosling\nc) Dennis Ritchie\nd) Bjarne Stroustrup");
        System.out.print("Your Answer: ");
        String ans1 = sc.nextLine();
        if (ans1.equalsIgnoreCase("b")) score++;

        // Q2
        System.out.println("\nQ2. Which component is used to compile, debug and execute Java programs?");
        System.out.println("a) JRE\nb) JIT\nc) JDK\nd) JVM");
        System.out.print("Your Answer: ");
        String ans2 = sc.nextLine();
        if (ans2.equalsIgnoreCase("c")) score++;

        // Q3
        System.out.println("\nQ3. What is the extension of Java code files?");
        System.out.println("a) .js\nb) .txt\nc) .class\nd) .java");
        System.out.print("Your Answer: ");
        String ans3 = sc.nextLine();
        if (ans3.equalsIgnoreCase("d")) score++;

        System.out.println("\n========================================");
        System.out.println("              QUIZ RESULTS              ");
        System.out.println("========================================");
        SimpleDateFormat formatter = new SimpleDateFormat("EEEE, dd MMMM yyyy HH:mm");
        System.out.println("Submitted at: " + formatter.format(new Date()));
        System.out.println("Total Score : " + score + " / 3");
        System.out.println("Percentage  : " + ((score * 100.0) / 3.0) + "%");

        if (score == 3) {
            System.out.println("Remarks     : Excellent Work!");
        } else {
            System.out.println("Remarks     : Good attempt, keep learning!");
        }
        System.out.println("========================================");
        sc.close();
    }
}
